export function formatValue(v) {
  if (v === 0) return "FREE";
  if (v < 1) return `ВЈ${Math.round(v * 1000)}k`;
  return `ВЈ${v}m`;
}

export function getRatingColor(r) {
  if (r >= 93) return "#7c5f00";
  if (r >= 88) return "#155724";
  if (r >= 83) return "#856404";
  return "#555";
}

export function getRatingBg(r) {
  if (r >= 93) return "#ffe566";
  if (r >= 88) return "#c3e6cb";
  if (r >= 83) return "#fff3cd";
  return "#e0e0e0";
}

// 16 equal slots per difficulty вҖ” the wheel is the honest probability distribution.
// Mean budgets: easy ВЈ109m, normal ВЈ80m, hard ВЈ48m, expert ВЈ38m, brutal ВЈ23m.
export const DIFFICULTY_SLOTS = {
  easy:   [0, 25, 50, 75, 75, 100, 100, 100, 125, 125, 125, 150, 150, 175, 175, 200],
  normal: [0, 25, 25, 50, 50, 50, 75, 75, 75, 75, 100, 100, 125, 125, 150, 175],
  hard:   [0, 0, 0, 25, 25, 25, 25, 50, 50, 50, 50, 75, 75, 100, 100, 125],
  expert: [0, 0, 0, 25, 25, 25, 25, 25, 25, 50, 50, 50, 50, 75, 75, 100],
  brutal: [0, 0, 0, 0, 0, 0, 25, 25, 25, 25, 25, 25, 50, 50, 50, 75],
};

export const DIFFICULTY_LABELS = {
  easy: "Easy", normal: "Normal", hard: "Hard", expert: "Expert", brutal: "Brutal",
};

export function generateBudget(difficulty = "normal") {
  const slots = DIFFICULTY_SLOTS[difficulty] || DIFFICULTY_SLOTS.normal;
  return slots[Math.floor(Math.random() * slots.length)];
}

